SELECT product_name, average_rating
FROM products
WHERE average_rating IN (
    (SELECT MAX(average_rating) FROM products),
    (SELECT MIN(average_rating) FROM products)
);

SELECT COUNT(variation_id) AS TotalFeaturedVariations
FROM product_variations
WHERE is_featured = 1;

SELECT *
FROM product_variations
WHERE CAST(price AS REAL) > (SELECT AVG(CAST(price AS REAL)) FROM product_variations);

SELECT variation_id, price
FROM product_variations
WHERE CAST(price AS REAL) > 200;

SELECT AVG(price) AS Average_Price
FROM product_variations
WHERE price > (
    SELECT AVG(price)
    FROM product_variations
);

SELECT DISTINCT u.user_name
FROM users u
INNER JOIN price_history h ON u.user_name = h.changed_by;

SELECT variation_id, product_id, color_name, size, material, image_url, price, stock_quantity, is_featured, reorder_level, last_reorder_date, supplier_id
FROM product_variations
WHERE price > (SELECT AVG(price) FROM product_variations);

SELECT products.product_name, product_variations.price
FROM products
INNER JOIN product_variations ON products.product_id = product_variations.product_id;

SELECT COUNT(*) AS variations_priced_higher_than_500
FROM price_history
WHERE CAST(new_price AS FLOAT) > 500.00;
